#include <stdio.h>
int process_file() {
  FILE *f = fopen("example.txt", "r");
  if (!f) return 1;
  int c = fgetc(f); // Use file before closing
  fclose(f);
  f = NULL; // Set to NULL after closing
  return 0;
}

FILE *f = fopen("test.txt", "w");
if (f) {
  fputs("data", f);
  fclose(f);
  f = NULL;
}
